-- =============================================================================
-- seed.sql
-- Access reference/configuration seed extracted from
-- legacy-db/YPLogicCurrentConsolidated.accdb with mdbtools.
--
-- Includes: application/config rows, lookup tables, tax/exchange/rate tables,
-- rooms, inventory, and Access query-helper tables.
-- Excludes: production guest/reservation/occupancy/payment/transaction/history
-- tables because they contain PII and old payment-card fields. Use
-- supabase/tools/export_access_data.py for the complete local import.
-- =============================================================================

set search_path = ypl, public;

truncate table
  ypl.application_information,
  ypl.application_information_from_back,
  ypl.application_objects,
  ypl.application_registration,
  ypl.application_specifications,
  ypl.application_versions,
  ypl.lookup_cities,
  ypl.lookup_countries,
  ypl.lookup_guest_diets,
  ypl.lookup_inventory_codes,
  ypl.lookup_inventory_types,
  ypl.lookup_payment_categories,
  ypl.lookup_payment_codes,
  ypl.lookup_payment_types,
  ypl.lookup_phone_fax_types,
  ypl.lookup_regions,
  ypl.lookup_room_rate_codes,
  ypl.lookup_room_rate_types,
  ypl.lookup_room_types,
  ypl.lookup_salutations,
  ypl.lookup_shuttle_sites,
  ypl.lookup_tax_rate_types,
  ypl.lookup_transaction_types,
  ypl.lookup_users,
  ypl.exchange_rates,
  ypl.tax_rates,
  ypl.rooms,
  ypl.room_rates,
  ypl.room_rates_new,
  ypl.inventory_items,
  ypl.inventory_excel_import,
  ypl.payment_type_zero,
  ypl.payment_zero,
  ypl.inventory_rates,
  ypl.inventory_rates_2,
  ypl.calc_tax_rate_filters,
  ypl.calc_tax_rate_filters_2,
  ypl.choose_room_rates,
  ypl.choose_room_rates_2,
  ypl.inventory_taxes,
  ypl.inventory_taxes_2
restart identity cascade;

-- ---- tblApplicationInformation -> ypl.application_information ----
INSERT INTO "ypl"."application_information" ("softwarename", "softwarenamelong", "version", "copyrightdate", "technicalsupport", "processor", "operatingsystem", "ram", "harddrive", "softwarerequirement", "projectcompletiondate", "developerfirstname", "developerlastname", "developercompanyname", "developerphone", "developerfax", "developeremail", "developerwebsite", "developerlogo", "developerlogoalternate", "developercompanyinfo", "archivecomments") VALUES ('YPLogic','YPLogic','C8','2010-02-17 00:00:00','Technical support is available via phone or email.   On-site  support is also available.  If you are 30 days past the completion date you will be charged at the developers current hourly or per diem rate (please contact the developer for current rates).  30 days after the completion of the application, all rates, terms, and conditions are subject to change without notice.','500 MHz or higher','Windows XP/Vista/7','256 MB or higher','2 GB of free space','Access 2007','2010-03-15 00:00:00','Alex','Armstrong','TM NewMedia','(250) 475-0808','(250) 475-0858','Tim.Mock@tmnewmedia.com','www.tmnewmedia.com#http://www.tmnewmedia.com#','','',NULL,'In July 2018, we archived all Reservations with an Arrival Date on or before Dec 2016.
In Dec 2019, we archived all Reservations with an Arrival Date on or before Dec 2017.
In Aug 2023, we archived all Reservations with an Arrival Date on or before June 2022.');

