-- Keep serial sequences ahead of seeded Access IDs.
select setval(
  pg_get_serial_sequence('ypl.application_registration', 'registrationid'),
  coalesce((select max(registrationid) from ypl.application_registration), 1),
  (select max(registrationid) is not null from ypl.application_registration)
);
select setval(
  pg_get_serial_sequence('ypl.application_specifications', 'specid'),
  coalesce((select max(specid) from ypl.application_specifications), 1),
  (select max(specid) is not null from ypl.application_specifications)
);
select setval(
  pg_get_serial_sequence('ypl.application_versions', 'versionid'),
  coalesce((select max(versionid) from ypl.application_versions), 1),
  (select max(versionid) is not null from ypl.application_versions)
);
select setval(
  pg_get_serial_sequence('ypl.exchange_rates', 'exchangerateid'),
  coalesce((select max(exchangerateid) from ypl.exchange_rates), 1),
  (select max(exchangerateid) is not null from ypl.exchange_rates)
);
select setval(
  pg_get_serial_sequence('ypl.inventory_items', 'inventoryid'),
  coalesce((select max(inventoryid) from ypl.inventory_items), 1),
  (select max(inventoryid) is not null from ypl.inventory_items)
);
select setval(
  pg_get_serial_sequence('ypl.lookup_users', 'userid'),
  coalesce((select max(userid) from ypl.lookup_users), 1),
  (select max(userid) is not null from ypl.lookup_users)
);
select setval(
  pg_get_serial_sequence('ypl.rooms', 'roomid'),
  coalesce((select max(roomid) from ypl.rooms), 1),
  (select max(roomid) is not null from ypl.rooms)
);
select setval(
  pg_get_serial_sequence('ypl.room_rates', 'roomrateid'),
  coalesce((select max(roomrateid) from ypl.room_rates), 1),
  (select max(roomrateid) is not null from ypl.room_rates)
);
select setval(
  pg_get_serial_sequence('ypl.room_rates_new', 'roomrateid'),
  coalesce((select max(roomrateid) from ypl.room_rates_new), 1),
  (select max(roomrateid) is not null from ypl.room_rates_new)
);
select setval(
  pg_get_serial_sequence('ypl.tax_rates', 'taxrateid'),
  coalesce((select max(taxrateid) from ypl.tax_rates), 1),
  (select max(taxrateid) is not null from ypl.tax_rates)
);
select setval(
  pg_get_serial_sequence('ypl.calc_tax_rate_filters', 'taxrateid'),
  coalesce((select max(taxrateid) from ypl.calc_tax_rate_filters), 1),
